@prefix sosa:       <http://www.w3.org/ns/sosa/> .
@prefix ssn:        <http://www.w3.org/ns/ssn/> .
@prefix ssn-system: <http://www.w3.org/ns/ssn/systems/> .
@prefix vann:       <http://purl.org/vocab/vann/> .
@prefix xsd:        <http://www.w3.org/2001/XMLSchema#> .

:InstallationShape  rdf:type  sh:NodeShape ;
        sh:property     [ sh:class        adms:Status ;
                          sh:description  "A system must have a single status"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         adms:status
                        ] ;
        sh:property     [ sh:description  "A system can have at most 1 geometry"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ogc:hasGeometry
                        ] ;
        sh:property     [ sh:class        :Process ;
                          sh:description  "An installation can also contain processes that this installation implements"@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ssn:implements
                        ] ;
        sh:property     [ sh:datatype     xsd:dateTime ;
                          sh:description  "A system must have a creation date"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:created
                        ] ;
        sh:property     [ sh:class        ssn:System ;
                          sh:description  "A system can contain multiple objects."@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ssn:hasSubSystem
                        ] ;
        sh:property     [ sh:class     ssn:System ;
                          sh:minCount  "0"^^xsd:int ;
                          sh:path      [ sh:inversePath  ssn:hasSubSystem ]
                        ] ;
        sh:property     [ sh:datatype     xsd:dateTime ;
                          sh:description  "A system must have a modification date"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:modified
                        ] ;
        sh:property     [ sh:class        adms:Identifier ;
                          sh:description  "A system has external identifiers (optional)"@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         adms:identifier
                        ] ;
        sh:property     [ sh:class        ssn:System ;
                          sh:description  "A system can be a revision of other systems (optional)"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         prov:wasRevisionOf
                        ] ;
        sh:property     [ sh:description  "A system must have a label"@en ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         rdfs:label
                        ] ;
        sh:property     [ sh:datatype     xsd:date ;
                          sh:description  "A system can have a validity end"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dc:valid
                        ] ;
        sh:property     [ sh:class        :Section ;
                          sh:description  "An installation can have multiple sections"@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         :section
                        ] ;
        sh:property     [ sh:class        :InstallationProperty ;
                          sh:description  "An installation can have multiple installation properties"@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ssn:hasProperty
                        ] ;
        sh:property     [ sh:datatype     xsd:date ;
                          sh:description  "A system must have a validity start"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:issued
                        ] ;
        sh:property     [ sh:class        :OperationLocation ;
                          sh:description  "A system must be part of a location"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         sosa:isHostedBy
                        ] ;
        sh:property     [ sh:class     :Operation ;
                          sh:minCount  "0"^^xsd:int ;
                          sh:path      ssn:hasDeployment
                        ] ;
        sh:property     [ sh:description  "A system can have a type via dct:type"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dc:type
                        ] ;
        sh:targetClass  :Installation .

:EmissionPointShape  rdf:type  sh:NodeShape ;
        sh:property     [ sh:datatype     xsd:date ;
                          sh:description  "A system must have a validity start"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:issued
                        ] ;
        sh:property     [ sh:description  "An emission point of type discharge point can have a depth"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dbo:depth
                        ] ;
        sh:property     [ sh:class     ssn:System ;
                          sh:minCount  "0"^^xsd:int ;
                          sh:path      [ sh:inversePath  ssn:hasSubSystem ]
                        ] ;
        sh:property     [ sh:class        adms:Status ;
                          sh:description  "A system must have a single status"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         adms:status
                        ] ;
        sh:property     [ sh:class        :OperationLocation ;
                          sh:description  "A system must be part of a location"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         sosa:isHostedBy
                        ] ;
        sh:property     [ sh:description  "An emission point of type stack has a diameter"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dbo:diameter
                        ] ;
        sh:property     [ sh:description  "An emission point of type stack has a height"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dbo:height
                        ] ;
        sh:property     [ sh:class        ssn:System ;
                          sh:description  "A system can contain multiple objects."@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ssn:hasSubSystem
                        ] ;
        sh:property     [ sh:description  "A system can have a type via dct:type"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dc:type
                        ] ;
        sh:property     [ sh:datatype     xsd:dateTime ;
                          sh:description  "A system must have a modification date"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:modified
                        ] ;
        sh:property     [ sh:class        adms:Identifier ;
                          sh:description  "A system has external identifiers (optional)"@en ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         adms:identifier
                        ] ;
        sh:property     [ sh:datatype     xsd:date ;
                          sh:description  "A system can have a validity end"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         dc:valid
                        ] ;
        sh:property     [ sh:description  "A system can have at most 1 geometry"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         ogc:hasGeometry
                        ] ;
        sh:property     [ sh:description  "A system must have a label"@en ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         rdfs:label
                        ] ;
        sh:property     [ sh:class        ssn:System ;
                          sh:description  "A system can be a revision of other systems (optional)"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "0"^^xsd:int ;
                          sh:path         prov:wasRevisionOf
                        ] ;
        sh:property     [ sh:class     :Operation ;
                          sh:minCount  "0"^^xsd:int ;
                          sh:path      ssn:hasDeployment
                        ] ;
        sh:property     [ sh:datatype     xsd:dateTime ;
                          sh:description  "A system must have a creation date"@en ;
                          sh:maxCount     "1"^^xsd:int ;
                          sh:minCount     "1"^^xsd:int ;
                          sh:path         dc:created
                        ] ;
        sh:targetClass  :EmissionPoint .
","length":11637,"name":"SHACL Shapes 1-2/23 (2 shapes)","type":"text/turtle"}

{"content":"@prefix :           <https://example.org/ns/riepr#> .
@prefix adms:       <http://www.w3.org/ns/adms#> .
@prefix concept:    <https://example.org/id/concept/> .
@prefix dbo:        <http://dbpedia.org/ontology/> .
@prefix dc:         <http://purl.org/dc/terms/> .
@prefix dct:        <http://purl.org/dc/terms/> .
@prefix foaf:       <http://xmlns.com/foaf/0.1/> .
@prefix hydra:      <http://www.w3.org/ns/hydra/core#> .
@prefix locn:       <http://www.w3.org/ns/locn#> .
@prefix nace:       <http://data.europa.eu/ux2/nace2.1/> .
@prefix ogc:        <http://www.opengis.net/ont/geosparql#> .
@prefix org:        <http://www.w3.org/ns/org#> .
@prefix owl:        <http://www.w3.org/2002/07/owl#> .
@prefix pplan:      <http://purl.org/net/p-plan#> .
@prefix prov:       <http://www.w3.org/ns/prov#> .
@prefix qudt:       <http://qudt.org/schema/qudt/> .
@prefix rdf:        <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs:       <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos:       <http://www.w3.org/2004/02/skos/core#> .
@prefix sosa:       <http://www.w3.org/ns/sosa/> .
@prefix ssn:        <http://www.w3.org/ns/ssn/> .
@prefix ssn-system: <http://www.w3.org/ns/ssn/systems/> .
@prefix vann:       <http://purl.org/vocab/vann/> .
@prefix xsd:        <http://www.w3.org/2001/XMLSchema#> .

[ rdf:type            owl:Class ;
  rdfs:comment        "A process with a ProcessingProcedure must process substances within an installation"@en ;
  rdfs:subClassOf     [ rdf:type            owl:Restriction ;
                        owl:onProperty      ssn:implementedBy ;
                        owl:someValuesFrom  :Installation
                      ] ;
  owl:intersectionOf  ( :Process
                        [ rdf:type            owl:Restriction ;
                          owl:someValuesFrom  :VerwerkingProcedure
                        ]
                      )
] .

:inactief  rdf:type           skos:Concept , adms:Status ;
        rdfs:comment          "The inactive status indicates that an entity is currently not in use."@en ;
        rdfs:equivalentClass  <http://purl.org/adms/status/Deprecated> ;
        rdfs:label            "Inactive"@en ;
        skos:prefLabel        "Inactive"@en .

:Filter  rdf:type        owl:Class ;
        rdfs:comment     "A filter is a specific system that is used to improve the quality of emissions by removing or reducing harmful substances."@en ;
        rdfs:label       "Filter"@en ;
        rdfs:subClassOf  ogc:SpatialObject , ssn:System ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have a validity end"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:valid ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasDeployment ;
                           owl:someValuesFrom  :Operation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can be a revision of other systems (optional)"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasRevisionOf ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a modification date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:modified ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system has external identifiers (optional)"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:identifier ;
                           owl:someValuesFrom  adms:Identifier
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have a type via dct:type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:type
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a validity start"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:issued ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a single status"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:status ;
                           owl:someValuesFrom  adms:Status
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have at most 1 geometry"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ogc:hasGeometry
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can contain multiple objects."@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasSubSystem ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a creation date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:created ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      [ rdf:type       owl:ObjectProperty ;
                                                 owl:inverseOf  ssn:hasSubSystem
                                               ] ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a label"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must be part of a location"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:isHostedBy ;
                           owl:someValuesFrom  :OperationLocation
                         ] .

:EmissionProcedure  rdf:type  skos:Concept , owl:Class ;
        rdfs:comment     "An emission procedure is a specific procedure that relates to the release or discharge of substances at emission points."@en ;
        rdfs:label       "Emission Procedure"@en ;
        rdfs:subClassOf  :TransportProcedure .

:ConsumptionProcedure
        rdf:type         skos:Concept , owl:Class ;
        rdfs:comment     "A consumption procedure is a specific procedure that relates to the transport of raw materials within a process."@en ;
        rdfs:label       "Consumption Procedure"@en ;
        rdfs:subClassOf  :TransportProcedure .

:voorgesteld  rdf:type        skos:Concept , adms:Status ;
        rdfs:comment          "The proposed status indicates that an entity has been proposed by the government but has not yet been confirmed."@en ;
        rdfs:equivalentClass  <http://purl.org/adms/status/UnderDevelopment> ;
        rdfs:label            "Proposed"@en ;
        skos:prefLabel        "Proposed"@en .

:WithdrawalPoint  rdf:type  owl:Class ;
        rdfs:comment     "A withdrawal point is a point where raw materials are extracted or sampled (withdrawal)."@en ;
        rdfs:label       "Withdrawal Point"@en ;
        rdfs:subClassOf  ogc:SpatialObject , ssn:System ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A withdrawal point can have a depth"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dbo:depth
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      [ rdf:type       owl:ObjectProperty ;
                                                 owl:inverseOf  ssn:hasSubSystem
                                               ] ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a modification date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:modified ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have at most 1 geometry"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ogc:hasGeometry
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have a type via dct:type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:type
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can be a revision of other systems (optional)"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasRevisionOf ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type          owl:Restriction ;
                           rdfs:comment      "A withdrawal point is different from an emission point (disjoint)"@en ;
                           owl:disjointWith  :Emissionpunt
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a label"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system has external identifiers (optional)"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:identifier ;
                           owl:someValuesFrom  adms:Identifier
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a single status"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:status ;
                           owl:someValuesFrom  adms:Status
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a creation date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:created ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must be part of a location"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:isHostedBy ;
                           owl:someValuesFrom  :OperationLocation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A withdrawal point can have filters"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasSubSystem ;
                           owl:someValuesFrom  :Filter
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a validity start"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:issued ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can contain multiple objects."@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasSubSystem ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasDeployment ;
                           owl:someValuesFrom  :Operation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can have a validity end"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:valid ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        skos:example     [ rdf:type    :WithdrawalPoint ;
                           rdfs:label  "Withdrawal 1"@en
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  dc:created ;
                                             hydra:required  true ;
                                             hydra:variable  "created"
                                           ] ;
                           hydra:mapping   [ hydra:property  dc:issued ;
                                             hydra:required  true ;
                                             hydra:variable  "issued"
                                           ] ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/onttrekkingspunt/{uuid}/{issued}/{created}"^^hydra:Rfc6570Template
                         ] .

:Section  rdf:type       owl:Class ;
        rdfs:comment     "A section is a specific classification that is used to categorize activities according to regulations."@en ;
        rdfs:label       "Section"@en ;
        rdfs:subClassOf  skos:Concept ;
