                           owl:onProperty      dc:valid ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system can be a revision of other systems (optional)"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasRevisionOf ;
                           owl:someValuesFrom  ssn:System
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a single status"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:status ;
                           owl:someValuesFrom  adms:Status
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:hasDeployment ;
                           owl:someValuesFrom  :Operation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a label"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must have a validity start"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:issued ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A system must be part of a location"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:isHostedBy ;
                           owl:someValuesFrom  :OperationLocation
                         ] .

:Observation  rdf:type   owl:Class ;
        rdfs:comment     "An observation is a measurement or observation that was performed at a measurement point."@en ;
        rdfs:label       "Observation"@en ;
        rdfs:subClassOf  sosa:Observation ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An observation must have a result."@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:hasResult ;
                           owl:someValuesFrom  sosa:Result
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An observation must be linked to exactly one measurement point or installation"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      sosa:hasFeatureOfInterest ;
                           owl:someValuesFrom  :Emission
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/observatie/{uuid}"^^hydra:Rfc6570Template
                         ] .

:section  rdf:type    owl:ObjectProperty ;
        rdfs:comment  "The VLAREM section that applies to a process or installation."@en ;
        rdfs:domain   [ rdf:type      owl:Class ;
                        rdfs:comment  "The VLAREM section can apply to processes"@en ;
                        owl:unionOf   ( :Installation )
                      ] ;
        rdfs:label    "VLAREM Section"@en ;
        rdfs:range    :Section .

:TransportProcedure  rdf:type  skos:Concept , owl:Class ;
        rdfs:comment     "A transport procedure is a specific procedure that relates to the transport of substances within or outside a process."@en ;
        rdfs:label       "Transport Procedure"@en ;
        rdfs:subClassOf  sosa:Procedure .

:gesloten  rdf:type           skos:Concept , adms:Status ;
        rdfs:comment          "The closed status indicates that an entity has been permanently taken out of service."@en ;
        rdfs:equivalentClass  <http://purl.org/adms/status/Withdrawn> ;
        rdfs:label            "Closed"@en ;
        skos:prefLabel        "Closed"@en .

:ProcessVariable  rdf:type  owl:Class ;
        rdfs:comment     "A process variable is a variable data that serves as input or output of a process."@en ;
        rdfs:label       "Process Variable"@en ;
        rdfs:subClassOf  pplan:Variable ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A process variable can have a label"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A process variable can have a value"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      qudt:numericValue
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A process variable can have a unit"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      qudt:hasUnit
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      pplan:isOutputVarOf ;
                           owl:someValuesFrom  :Process
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      pplan:isInputVarOf ;
                           owl:someValuesFrom  :Process
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "A process variable can have a type via dct:type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:type
                         ] ;
        skos:example     [ rdf:type    :ProcessVariabele ;
                           rdfs:label  "Flour"@en ;
                           dc:type     [ rdf:type    prov:Entity ;
                                         rdfs:label  "Substance"@en
                                       ]
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/procesvariabele/{uuid}"^^hydra:Rfc6570Template
                         ] .

[ rdf:type            owl:Class ;
  rdfs:comment        "A process with a measurement procedure must perform measurements at a measurement point"@en ;
  rdfs:subClassOf     [ rdf:type            owl:Restriction ;
                        owl:onProperty      ssn:implementedBy ;
                        owl:someValuesFrom  :MeasurementPoint
                      ] ;
  owl:intersectionOf  ( :Process
                        [ rdf:type            owl:Restriction ;
                          owl:someValuesFrom  :MeetProcedure
                        ]
                      )
] .

:Emission  rdf:type          owl:Class ;
        rdfs:comment         "An emission is a specific result that relates to the release or discharge of substances at emission points."@en ;
        rdfs:label           "Emission"@en ;
        rdfs:subClassOf      sosa:Result ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      sosa:isResultOf ;
                               owl:someValuesFrom  sosa:Observation
                             ] ;
        owl:equivalentClass  [ rdf:type            owl:Restriction ;
                               rdfs:comment        "An emission must be linked to a process variable that is used within a process (as output) that is implemented by an emission point"@en ;
                               owl:onProperty      pplan:correspondsToVariable ;
                               owl:someValuesFrom  [ rdf:type            owl:Restriction ;
                                                     owl:onProperty      pplan:isOutputVarOf ;
                                                     owl:someValuesFrom  [ rdf:type            owl:Restriction ;
                                                                           owl:onProperty      ssn:implementedBy ;
                                                                           owl:someValuesFrom  :Emissionpunt
                                                                         ]
                                                   ]
                             ] .

:OperatorContactPerson
        rdf:type         owl:Class ;
        rdfs:comment     "An operator contact person is a person who acts as a contact person for an operator."@en ;
        rdfs:label       "Operator Contact Person"@en ;
        rdfs:subClassOf  foaf:Person ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person must have a role within the organization"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      org:hasRole
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person must have a name"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      foaf:name
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a creation date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:created ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a comment"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:comment
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a validity end"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:valid ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have an email address"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      foaf:mbox
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      org:memberOf ;
                           owl:someValuesFrom  :Operation , :Operator
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person must have a label"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a validity start"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:issued ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a phone number"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      foaf:phone
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person can have a modification date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:modified ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  dc:created ;
                                             hydra:required  true ;
                                             hydra:variable  "created"
                                           ] ;
                           hydra:mapping   [ hydra:property  dc:issued ;
                                             hydra:required  true ;
                                             hydra:variable  "issued"
                                           ] ;
                           hydra:mapping   [ hydra:property  :localId ;
                                             hydra:required  true ;
                                             hydra:variable  "uuid"
                                           ] ;
                           hydra:template  "https://example.org/id/contactpersoon/{uuid}/{issued}/{created}"^^hydra:Rfc6570Template
                         ] .
