                               sosa:isHostedBy  [ rdf:type    :OperationLocation ;
                                                  rdfs:label  "Cement factory Antwerp"@en
                                                ]
                             ] ;
        skos:example         [ rdf:type    :Process ;
                               rdfs:label  "Processing of raw materials"@en ;
                               dc:type     [ rdf:type  :VerwerkingProcedure ]
                             ] ;
        hydra:search         [ rdf:type        hydra:IriTemplate ;
                               hydra:mapping   [ hydra:property  dc:created ;
                                                 hydra:required  true ;
                                                 hydra:variable  "created"
                                               ] ;
                               hydra:mapping   [ hydra:property  dc:issued ;
                                                 hydra:required  true ;
                                                 hydra:variable  "issued"
                                               ] ;
                               hydra:mapping   [ hydra:property  :localId ;
                                                 hydra:required  true ;
                                                 hydra:variable  "localId"
                                               ] ;
                               hydra:template  "https://example.org/id/proces/{localId}/{issued}/{created}"^^hydra:Rfc6570Template
                             ] .

pplan:isOutputVarOf  owl:inverseOf  pplan:hasOutputVar .

[ rdf:type            owl:Class ;
  rdfs:comment        "A process with an emission procedure must release or discharge substances at an emission point"@en ;
