        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An installation property must have a value"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      qudt:numericValue
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An installation property must have a type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:type
                         ] .

:OperationLocation  rdf:type  owl:Class ;
        rdfs:comment     "An operation location is a specific geographic location where an operator carries out its processes."@en ;
