                           owl:onProperty      ssn:isPropertyOf ;
                           owl:someValuesFrom  :Installation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An installation property must have a unit"@en ;
