                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      qudt:hasUnit
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An installation property must have a value"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      qudt:numericValue
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An installation property must have a type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:type
                         ] .

:OperationLocation  rdf:type  owl:Class ;
        rdfs:comment     "An operation location is a specific geographic location where an operator carries out its processes."@en ;
        rdfs:label       "Operation Location"@en ;
        rdfs:subClassOf  ogc:Feature , sosa:Platform , prov:Entity ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must have exactly 1 geometry"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ogc:hasGeometry
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must have a validity start"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:issued ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location can have an address"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      locn:address ;
                           owl:someValuesFrom  locn:Address
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location can have a validity end"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:valid ;
                           owl:someValuesFrom  xsd:date
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must have a modification date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:modified ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must be linked to exactly one operator"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasAttributedTo ;
                           owl:someValuesFrom  :Operator
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location can be a revision of another operation location (optional)"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasRevisionOf ;
                           owl:someValuesFrom  :OperationLocation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must have a label"@en ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      rdfs:label
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      ssn:inDeployment ;
                           owl:someValuesFrom  :Operation
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location must have a creation date"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:onProperty      dc:created ;
                           owl:someValuesFrom  xsd:dateTime
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location has external identifiers (optional)"@en ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      adms:identifier ;
                           owl:someValuesFrom  adms:Identifier
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location can optionally be influenced by an org:Site or another type"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:wasInfluencedBy
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operation location can match one location (VKBO)"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      prov:hadPrimarySource ;
                           owl:someValuesFrom  org:Site
                         ] ;
        skos:example     [ rdf:type               :OperationLocation ;
                           rdfs:label             "Cement factory Antwerp"@en ;
                           prov:hadPrimarySource  [ rdf:type    org:Site ;
                                                    rdfs:label  "VKBO Location Cement factory"@en
                                                  ]
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  dc:created ;
                                             hydra:required  true ;
                                             hydra:variable  "created"
                                           ] ;
                           hydra:mapping   [ hydra:property  dc:issued ;
                                             hydra:required  true ;
                                             hydra:variable  "issued"
                                           ] ;
                           hydra:mapping   [ hydra:property  owl:sameAs ;
                                             hydra:required  true ;
                                             hydra:variable  "geoId"
                                           ] ;
                           hydra:template  "https://example.org/id/exploitatielocatie/{geoId}/{issued}/{created}"^^hydra:Rfc6570Template
                         ] .

