        rdfs:comment     "A measurement point is a specific point where measurements are performed to monitor the quality of emissions or the environment."@en ;
        rdfs:label       "Measurement Point"@en ;
        rdfs:subClassOf  ogc:SpatialObject , ssn:System ;
